def write_partition_to_api(partition):
    import requests
    records = list(partition)
    for record in records:
        requests.post(
            "https://events-api.internal/ingest",
            json=record.asDict(),
            timeout=10
        )
    return iter([len(records)])

df_events.rdd.mapPartitions(write_partition_to_api).collect()
